import { useState, useRef, useCallback, useEffect } from 'react';
import './ArtifactCard.css';

/* ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
export interface Artifact {
    id: string;
    title: string;
    titleTr?: string;
    date: string;
    category: 'books' | 'portraits' | 'documents' | 'objects';
    description: string;
    descriptionTr?: string;
    imageSrc: string;
    provenance?: string;
}

interface ArtifactCardProps {
    artifact: Artifact;
    /** All artifacts in the grid ΓÇö passed so CuratorView can navigate */
    allArtifacts?: Artifact[];
}

/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
   CURATOR VIEW ΓÇö full-screen lightbox with pan & zoom
   ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */
interface CuratorViewProps {
    artifact: Artifact;
    allArtifacts: Artifact[];
    onClose: () => void;
    onNavigate: (artifact: Artifact) => void;
}

function CuratorView({ artifact, allArtifacts, onClose, onNavigate }: CuratorViewProps) {
    const [scale, setScale] = useState(1);
    const [position, setPosition] = useState({ x: 0, y: 0 });
    const [isDragging, setIsDragging] = useState(false);
    const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
    const [lastPinchDist, setLastPinchDist] = useState<number | null>(null);
    const imageContainerRef = useRef<HTMLDivElement>(null);

    const MIN_SCALE = 1;
    const MAX_SCALE = 4;

    const currentIndex = allArtifacts.findIndex(a => a.id === artifact.id);
    const hasPrev = currentIndex > 0;
    const hasNext = currentIndex < allArtifacts.length - 1;

    // Reset zoom when artifact changes
    useEffect(() => {
        setScale(1);
        setPosition({ x: 0, y: 0 });
    }, [artifact.id]);

    // Keyboard navigation
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            switch (e.key) {
                case 'Escape':
                    onClose();
                    break;
                case 'ArrowLeft':
                    if (hasPrev) onNavigate(allArtifacts[currentIndex - 1]);
                    break;
                case 'ArrowRight':
                    if (hasNext) onNavigate(allArtifacts[currentIndex + 1]);
                    break;
                case '+':
                case '=':
                    setScale(s => Math.min(s + 0.5, MAX_SCALE));
                    break;
                case '-':
                    setScale(s => Math.max(s - 0.5, MIN_SCALE));
                    break;
                case '0':
                    setScale(1);
                    setPosition({ x: 0, y: 0 });
                    break;
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [onClose, hasPrev, hasNext, currentIndex, allArtifacts, onNavigate]);

    // Prevent body scroll when lightbox is open
    useEffect(() => {
        document.body.style.overflow = 'hidden';
        return () => { document.body.style.overflow = ''; };
    }, []);

    /* ΓöÇΓöÇ Zoom via mouse wheel ΓöÇΓöÇ */
    const handleWheel = useCallback((e: React.WheelEvent) => {
        e.preventDefault();
        const delta = e.deltaY > 0 ? -0.25 : 0.25;
        setScale(s => {
            const newScale = Math.max(MIN_SCALE, Math.min(s + delta, MAX_SCALE));
            if (newScale === 1) setPosition({ x: 0, y: 0 });
            return newScale;
        });
    }, []);

    /* ΓöÇΓöÇ Double-click to toggle zoom ΓöÇΓöÇ */
    const handleDoubleClick = useCallback((e: React.MouseEvent) => {
        if (scale > 1) {
            setScale(1);
            setPosition({ x: 0, y: 0 });
        } else {
            // Zoom to 2.5x centered on click point
            const rect = imageContainerRef.current?.getBoundingClientRect();
            if (rect) {
                const x = e.clientX - rect.left - rect.width / 2;
                const y = e.clientY - rect.top - rect.height / 2;
                setScale(2.5);
                setPosition({ x: -x * 1.5, y: -y * 1.5 });
            }
        }
    }, [scale]);

    /* ΓöÇΓöÇ Drag to pan ΓöÇΓöÇ */
    const handleMouseDown = useCallback((e: React.MouseEvent) => {
        if (scale <= 1) return;
        e.preventDefault();
        setIsDragging(true);
        setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y });
    }, [scale, position]);

    const handleMouseMove = useCallback((e: React.MouseEvent) => {
        if (!isDragging) return;
        setPosition({
            x: e.clientX - dragStart.x,
            y: e.clientY - dragStart.y,
        });
    }, [isDragging, dragStart]);

    const handleMouseUp = useCallback(() => {
        setIsDragging(false);
    }, []);

    /* ΓöÇΓöÇ Touch: pinch-to-zoom + drag ΓöÇΓöÇ */
    const getTouchDist = (touches: React.TouchList) => {
        const dx = touches[0].clientX - touches[1].clientX;
        const dy = touches[0].clientY - touches[1].clientY;
        return Math.sqrt(dx * dx + dy * dy);
    };

    const handleTouchStart = useCallback((e: React.TouchEvent) => {
        if (e.touches.length === 2) {
            setLastPinchDist(getTouchDist(e.touches));
        } else if (e.touches.length === 1 && scale > 1) {
            setIsDragging(true);
            setDragStart({
                x: e.touches[0].clientX - position.x,
                y: e.touches[0].clientY - position.y,
            });
        }
    }, [scale, position]);

    const handleTouchMove = useCallback((e: React.TouchEvent) => {
        if (e.touches.length === 2 && lastPinchDist !== null) {
            const newDist = getTouchDist(e.touches);
            const delta = (newDist - lastPinchDist) * 0.01;
            setScale(s => Math.max(MIN_SCALE, Math.min(s + delta, MAX_SCALE)));
            setLastPinchDist(newDist);
        } else if (e.touches.length === 1 && isDragging) {
            setPosition({
                x: e.touches[0].clientX - dragStart.x,
                y: e.touches[0].clientY - dragStart.y,
            });
        }
    }, [lastPinchDist, isDragging, dragStart]);

    const handleTouchEnd = useCallback(() => {
        setIsDragging(false);
        setLastPinchDist(null);
    }, []);

    const categoryLabels: Record<string, string> = {
        books: 'Kitaplar',
        portraits: 'Portreler',
        documents: 'Belgeler',
        objects: 'Objeler',
    };

    return (
        <div className="curator-overlay" onClick={onClose}>
            <div className="curator-content" onClick={(e) => e.stopPropagation()}>

                {/* Close button */}
                <button className="curator-close" onClick={onClose} aria-label="Close">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <line x1="18" y1="6" x2="6" y2="18" />
                        <line x1="6" y1="6" x2="18" y2="18" />
                    </svg>
                </button>

                {/* Navigation arrows */}
                {hasPrev && (
                    <button
                        className="curator-nav curator-nav--prev"
                        onClick={() => onNavigate(allArtifacts[currentIndex - 1])}
                        aria-label="Previous artifact"
                    >
                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <polyline points="15,18 9,12 15,6" />
                        </svg>
                    </button>
                )}
                {hasNext && (
                    <button
                        className="curator-nav curator-nav--next"
                        onClick={() => onNavigate(allArtifacts[currentIndex + 1])}
                        aria-label="Next artifact"
                    >
                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <polyline points="9,6 15,12 9,18" />
                        </svg>
                    </button>
                )}

                {/* Image viewport */}
                <div
                    ref={imageContainerRef}
                    className={`curator-viewport ${isDragging ? 'curator-viewport--dragging' : ''} ${scale > 1 ? 'curator-viewport--zoomed' : ''}`}
                    onWheel={handleWheel}
                    onDoubleClick={handleDoubleClick}
                    onMouseDown={handleMouseDown}
                    onMouseMove={handleMouseMove}
                    onMouseUp={handleMouseUp}
                    onMouseLeave={handleMouseUp}
                    onTouchStart={handleTouchStart}
                    onTouchMove={handleTouchMove}
                    onTouchEnd={handleTouchEnd}
                >
                    <img
                        src={artifact.imageSrc}
                        alt={artifact.title}
                        className="curator-image"
                        draggable={false}
                        style={{
                            transform: `translate(${position.x}px, ${position.y}px) scale(${scale})`,
                        }}
                    />
                </div>

                {/* Zoom controls */}
                <div className="curator-zoom-controls">
                    <button
                        className="curator-zoom-btn"
                        onClick={() => setScale(s => Math.max(MIN_SCALE, s - 0.5))}
                        aria-label="Zoom out"
                        disabled={scale <= MIN_SCALE}
                    >
                        ΓêÆ
                    </button>
                    <span className="curator-zoom-level">{Math.round(scale * 100)}%</span>
                    <button
                        className="curator-zoom-btn"
                        onClick={() => setScale(s => Math.min(MAX_SCALE, s + 0.5))}
                        aria-label="Zoom in"
                        disabled={scale >= MAX_SCALE}
                    >
                        +
                    </button>
                    <button
                        className="curator-zoom-btn curator-zoom-btn--reset"
                        onClick={() => { setScale(1); setPosition({ x: 0, y: 0 }); }}
                        aria-label="Reset zoom"
                    >
                        Γƒ│
                    </button>
                </div>

                {/* Metadata panel */}
                <div className="curator-meta">
                    <span className="curator-meta__category">
                        {categoryLabels[artifact.category] || artifact.category}
                    </span>
                    <h2 className="curator-meta__title">{artifact.title}</h2>
                    {artifact.titleTr && (
                        <p className="curator-meta__title-tr">{artifact.titleTr}</p>
                    )}
                    <p className="curator-meta__date">{artifact.date}</p>
                    <hr className="gold-divider" />
                    <p className="curator-meta__description">{artifact.description}</p>
                    {artifact.descriptionTr && (
                        <p className="curator-meta__description-tr">{artifact.descriptionTr}</p>
                    )}
                    {artifact.provenance && (
                        <p className="curator-meta__provenance">
                            <span>Kaynak:</span> {artifact.provenance}
                        </p>
                    )}
                    <p className="curator-meta__hint">
                        Scroll to zoom ┬╖ Double-click to magnify ┬╖ Drag to pan
                    </p>
                </div>
            </div>
        </div>
    );
}

/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
   ARTIFACT CARD ΓÇö the grid item
   ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */
export default function ArtifactCard({ artifact, allArtifacts = [] }: ArtifactCardProps) {
    const [showCurator, setShowCurator] = useState(false);
    const [activeArtifact, setActiveArtifact] = useState(artifact);

    const categoryLabels: Record<string, string> = {
        books: 'Kitaplar',
        portraits: 'Portreler',
        documents: 'Belgeler',
        objects: 'Objeler',
    };

    const categoryIcons: Record<string, string> = {
        books: '≡ƒôû',
        portraits: '≡ƒû╝∩╕Å',
        documents: '≡ƒô£',
        objects: '≡ƒÅ║',
    };

    const handleCardClick = () => {
        setActiveArtifact(artifact);
        setShowCurator(true);
    };

    const handleNavigate = (newArtifact: Artifact) => {
        setActiveArtifact(newArtifact);
    };

    const effectiveArtifacts = allArtifacts.length > 0 ? allArtifacts : [artifact];

    return (
        <>
            <article
                className="artifact-card"
                onClick={handleCardClick}
                tabIndex={0}
                role="button"
                aria-label={`View ${artifact.title} in Curator View`}
                onKeyDown={(e) => { if (e.key === 'Enter') handleCardClick(); }}
            >
                <div className="artifact-card__image-wrapper">
                    <img
                        src={artifact.imageSrc}
                        alt={artifact.title}
                        className="artifact-card__image"
                        loading="lazy"
                    />
                    <div className="artifact-card__overlay">
                        <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                            <circle cx="11" cy="11" r="7" />
                            <line x1="16.5" y1="16.5" x2="21" y2="21" />
                            <line x1="11" y1="8" x2="11" y2="14" />
                            <line x1="8" y1="11" x2="14" y2="11" />
                        </svg>
                        <span>Curator View</span>
                    </div>
                </div>

                <div className="artifact-card__content">
                    <div className="artifact-card__category">
                        <span className="artifact-card__category-icon">
                            {categoryIcons[artifact.category]}
                        </span>
                        <span className="artifact-card__category-label">
                            {categoryLabels[artifact.category] || artifact.category}
                        </span>
                    </div>
                    <h3 className="artifact-card__title">{artifact.title}</h3>
                    {artifact.titleTr && (
                        <p className="artifact-card__title-tr">{artifact.titleTr}</p>
                    )}
                    <p className="artifact-card__date">{artifact.date}</p>
                    <hr className="artifact-card__divider" />
                    <p className="artifact-card__description">{artifact.description}</p>
                </div>
            </article>

            {showCurator && (
                <CuratorView
                    artifact={activeArtifact}
                    allArtifacts={effectiveArtifacts}
                    onClose={() => setShowCurator(false)}
                    onNavigate={handleNavigate}
                />
            )}
        </>
    );
}

